import{_ as t,o as r,c as s,a2 as o}from"./chunks/framework.BWuWLRhz.js";const d=JSON.parse('{"title":"Server Setup","description":"","frontmatter":{},"headers":[],"relativePath":"self-hosting/server-setup.md","filePath":"self-hosting/server-setup.md"}'),a={name:"self-hosting/server-setup.md"};function n(i,e,l,h,p,u){return r(),s("div",null,[...e[0]||(e[0]=[o('<h1 id="server-setup" tabindex="-1">Server Setup <a class="header-anchor" href="#server-setup" aria-label="Permalink to &quot;Server Setup&quot;">​</a></h1><p>After you <a href="/self-hosting/servers">register a server</a>, Tragwerk provisions it with an automated <strong>setup job</strong>. The job connects over SSH and prepares the host to run your applications.</p><h2 id="what-the-setup-job-provisions" tabindex="-1">What the setup job provisions <a class="header-anchor" href="#what-the-setup-job-provisions" aria-label="Permalink to &quot;What the setup job provisions&quot;">​</a></h2><ul><li><strong>Docker</strong> and Docker Compose on the host.</li><li><strong>Traefik</strong> as a host-level reverse proxy — it terminates TLS (Let&#39;s Encrypt) and routes public traffic to your application containers.</li><li>The shared external Docker network <strong><code>tragwerk-net</code></strong> that every application container joins so Traefik can reach it.</li></ul><p>After setup completes, the server is ready to receive deploys. See <a href="/self-hosting/architecture-on-host">Architecture on the Host</a> for what the running stack looks like.</p><h2 id="live-setup-logs-and-statuses" tabindex="-1">Live setup logs and statuses <a class="header-anchor" href="#live-setup-logs-and-statuses" aria-label="Permalink to &quot;Live setup logs and statuses&quot;">​</a></h2><p>Server setup runs asynchronously and streams <strong>live progress logs</strong> to the UI as it works. The job moves through these statuses:</p><ul><li><strong>Pending</strong> — queued, not yet started.</li><li><strong>Running</strong> — actively provisioning the host.</li><li><strong>Completed</strong> — the server is provisioned and ready.</li><li><strong>Failed</strong> — provisioning stopped on an error; check the logs.</li></ul><p>The UI updates in real time as setup progresses.</p><h2 id="running-setup" tabindex="-1">Running setup <a class="header-anchor" href="#running-setup" aria-label="Permalink to &quot;Running setup&quot;">​</a></h2><p>Setup is triggered entirely from the UI: open the server and start the setup job. Tragwerk connects over SSH and provisions the machine in the background while streaming progress to the page — there is nothing to run yourself.</p><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>If the SSH connection details or the selected credential are wrong, setup will <strong>Fail</strong> early. Verify the host, port, and that the <a href="/app/registries-credentials">credential</a> (SSH key or password) is correct and authorized on the server, then retry.</p></div><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="/self-hosting/servers">Servers</a></li><li><a href="/self-hosting/architecture-on-host">Architecture on the Host</a></li></ul>',14)])])}const g=t(a,[["render",n]]);export{d as __pageData,g as default};
